+  boost::shared_ptr<ros::MultiThreadedSpinner> spinner;
+  if(concurrency_level) {
+    spinner.reset(new ros::MultiThreadedSpinner(concurrency_level));
+  }else{
+    spinner.reset(new ros::MultiThreadedSpinner());
+  }
+  spinner->spin();
+  return 0;
+
+}

